const payload = $json.body ?? $json;

const core = payload.core ?? {};
const production = payload.production ?? {};
const ai = payload.ai ?? {};
const distribution = payload.distribution ?? {};
const pipeline = payload.pipeline ?? {};

const asArray = (value) => Array.isArray(value) ? value : value ? [value] : [];

return [{
  json: {
    rawPayload: payload,
    normalized: {
      campaign_name: core.campaignName ?? '',
      destination_brand: core.destinationBrand ?? '',
      content_type: production.contentType ?? '',
      format: production.format ?? '',
      resolution: production.resolution ?? '',
      aspect_ratio: production.aspectRatio ?? '',
      visual_style: production.visualStyle ?? '',
      visual_mood: production.visualMood ?? '',
      render_complexity: production.renderComplexity ?? '',
      hashtags: asArray(ai.hashtagSet),
      posting_windows: asArray(distribution.postingWindow),
      target_account_types: asArray(distribution.accountTypeTargets),
      pipeline_targets: asArray(pipeline.destinationPipeline),
      orchestration_stage: pipeline.automationStage ?? '',
      orchestration_status: pipeline.orchestrationStatus ?? ''
    },
    sections: {
      core,
      production,
      ai,
      distribution,
      pipeline
    }
  }
}];

const item = $json;
const { core, production, ai, distribution, pipeline } = item.sections;
const errors = [];
const warnings = [];

if (!core || Object.keys(core).length === 0) errors.push('missing core section');
if (!production || Object.keys(production).length === 0) errors.push('missing production section');
if (!ai || Object.keys(ai).length === 0) warnings.push('missing ai section');
if (!distribution || Object.keys(distribution).length === 0) warnings.push('missing distribution section');
if (!pipeline || Object.keys(pipeline).length === 0) errors.push('missing pipeline section');

if (!core.requestId) errors.push('missing core.requestId');
if (!core.campaignId) errors.push('missing core.campaignId');
if (!core.campaignName) warnings.push('missing core.campaignName');
if (!core.orchestrationVersion) warnings.push('missing core.orchestrationVersion');
if (!production.contentType) errors.push('missing production.contentType');
if (!production.format) warnings.push('missing production.format');
if (!production.resolution) warnings.push('missing production.resolution');
if (!production.visualStyle) warnings.push('missing production.visualStyle');
if (!pipeline.automationStage) warnings.push('missing pipeline.automationStage');
if (!Array.isArray(pipeline.destinationPipeline) || pipeline.destinationPipeline.length === 0) errors.push('missing pipeline.destinationPipeline');

const allowedPipelines = ['n8n', 'ComfyUI', 'AI Writer'];
const unsupportedPipelines = Array.isArray(pipeline.destinationPipeline)
  ? pipeline.destinationPipeline.filter((target) => !allowedPipelines.includes(target))
  : [];
if (unsupportedPipelines.length > 0) warnings.push(`unsupported pipeline targets: ${unsupportedPipelines.join(', ')}`);

const validated = errors.length === 0;
const validationStatus = validated ? (warnings.length ? 'warning' : 'valid') : 'failed';

return [{
  json: {
    ...item,
    validation: {
      validated,
      validationStatus,
      errors,
      warnings
    }
  }
}];

const item = $json;
const production = item.sections.production;
const pipeline = item.sections.pipeline;
const contentType = String(production.contentType ?? '');
const format = String(production.format ?? '');
const visualStyle = String(production.visualStyle ?? '');
const pipelineTargets = Array.isArray(pipeline.destinationPipeline) ? pipeline.destinationPipeline : [];
const text = `${contentType} ${format} ${visualStyle}`.toLowerCase();

let route = 'manual_review_only_sim';
let routeReason = 'No ComfyUI route matched. Keep this payload in manual review.';
let requiresComfyUI = false;
let outputIntent = 'manual orchestration review';

if (contentType === 'Generate Hero Reel' || (text.includes('reel') && text.includes('9:16'))) {
  route = 'comfyui_video_vertical_sim';
  routeReason = 'Hero reel or vertical reels format detected.';
  requiresComfyUI = true;
  outputIntent = 'vertical hero reel render specification';
} else if (contentType === 'Generate Carousel' || (text.includes('carousel') && text.includes('4:5'))) {
  route = 'comfyui_carousel_sim';
  routeReason = 'Carousel format detected.';
  requiresComfyUI = true;
  outputIntent = 'carousel visual render specification';
} else if (contentType === 'Generate Before-After' || text.includes('before-after') || text.includes('before after')) {
  route = 'comfyui_before_after_sim';
  routeReason = 'Before-after transformation content detected.';
  requiresComfyUI = true;
  outputIntent = 'before-after comparison render specification';
} else if (contentType === 'Generate Story Pack' || text.includes('story') || text.includes('stories')) {
  route = 'comfyui_story_pack_sim';
  routeReason = 'Story pack or stories format detected.';
  requiresComfyUI = true;
  outputIntent = 'vertical story pack render specification';
} else if (contentType === 'Generate AI Caption Batch' || text.includes('caption')) {
  route = 'ai_writer_only_sim';
  routeReason = 'Caption-only payload detected; no visual render required.';
  requiresComfyUI = false;
  outputIntent = 'caption batch orchestration specification';
}

if (!pipelineTargets.includes('ComfyUI')) {
  requiresComfyUI = false;
  if (route.startsWith('comfyui_')) routeReason += ' Pipeline does not include ComfyUI, so render remains disabled.';
}

return [{
  json: {
    ...item,
    routing: {
      route,
      routeReason,
      requiresComfyUI,
      outputIntent,
      contentType,
      format,
      visualStyle,
      pipelineTargets,
      simulationOnly: true
    }
  }
}];

const item = $json;
const { core, production, ai, distribution, pipeline } = item.sections;
const routing = item.routing;
const contentType = production.contentType ?? 'Unknown';
const batchText = String(distribution.estimatedBatch ?? '1');
const numericMatch = batchText.match(/\d+/);
const batchSize = numericMatch ? Number(numericMatch[0]) : Number(ai.variationCount ?? 1) || 1;
const promptParts = [
  ai.promptDirection,
  production.visualStyle ? `Visual style: ${production.visualStyle}` : '',
  production.visualMood ? `Mood: ${production.visualMood}` : '',
  core.materialTopic ? `Material/topic: ${core.materialTopic}` : '',
  core.destinationBrand ? `Destination brand: ${core.destinationBrand}` : ''
].filter(Boolean);

const renderSpec = {
  renderSpecId: `render-spec-${core.requestId || Date.now()}`,
  requestId: core.requestId ?? null,
  route: routing.route,
  contentType,
  format: production.format ?? null,
  resolution: production.resolution ?? null,
  aspectRatio: production.aspectRatio ?? null,
  visualStyle: production.visualStyle ?? null,
  visualMood: production.visualMood ?? null,
  renderComplexity: production.renderComplexity ?? null,
  promptDirection: promptParts.join(' | '),
  negativePrompt: 'no watermark, no distorted text, no broken architecture, no warped stone texture, no low quality render',
  batchSize,
  outputIntent: routing.outputIntent,
  targetPlatforms: Array.isArray(distribution.targetPlatforms) ? distribution.targetPlatforms : [],
  destinationPipeline: Array.isArray(pipeline.destinationPipeline) ? pipeline.destinationPipeline : [],
  requiresComfyUI: routing.requiresComfyUI,
  simulationOnly: true
};

const renderSpecPreview = {
  route: renderSpec.route,
  requiresComfyUI: renderSpec.requiresComfyUI,
  outputIntent: renderSpec.outputIntent,
  format: `${renderSpec.format || 'unknown'} / ${renderSpec.resolution || 'unknown'} / ${renderSpec.aspectRatio || 'unknown'}`,
  batchSize: renderSpec.batchSize,
  promptPreview: renderSpec.promptDirection.slice(0, 240)
};

return [{
  json: {
    ...item,
    renderSpec,
    renderSpecPreview
  }
}];

const item = $json;
const { core, production } = item.sections;
const renderSpec = item.renderSpec;
const isCaptionOnly = !renderSpec.requiresComfyUI || String(renderSpec.contentType ?? '').toLowerCase() === 'generate ai caption batch';
const batchCount = Math.max(1, Math.min(Number(renderSpec.batchSize || 1), isCaptionOnly ? 1 : 6));

const assets = Array.from({ length: batchCount }, (_, index) => {
  const sequence = String(index + 1).padStart(2, '0');
  const assetType = isCaptionOnly ? 'mock_caption_output' : 'mock_render_asset';
  const filenameBase = isCaptionOnly
    ? 'caption'
    : `${String(renderSpec.format || 'render').replace(/[^a-z0-9]+/gi, '-').toLowerCase()}-${String(renderSpec.aspectRatio || 'n-a').replace(/[^a-z0-9]+/gi, '-').toLowerCase()}`;

  return {
    assetId: `mock-asset-${core.requestId || 'request'}-${sequence}`,
    type: assetType,
    format: isCaptionOnly ? 'caption' : (renderSpec.format ?? null),
    resolution: isCaptionOnly ? 'text-only' : (renderSpec.resolution ?? null),
    aspectRatio: isCaptionOnly ? 'n/a' : (renderSpec.aspectRatio ?? null),
    filename: `${core.requestId || 'request'}-${filenameBase}-${sequence}.json`,
    mockUrl: null,
    storagePath: null,
    readyForPosting: false
  };
});

return [{
  json: {
    ...item,
    mockAssetResult: {
      status: 'mock_ready',
      simulationOnly: true,
      source: 'comfyui_connector_mock_phase1',
      renderSpecId: renderSpec.renderSpecId,
      requestId: core.requestId ?? null,
      assetBatchId: `mock-batch-${core.requestId || Date.now()}`,
      assets
    }
  }
}];

const item = $json;
const { core, production, ai, distribution, pipeline } = item.sections;
const pipelineTargets = Array.isArray(pipeline.destinationPipeline) ? pipeline.destinationPipeline : [];
const parsedSections = {
  core: {
    requestId: core.requestId ?? null,
    campaignId: core.campaignId ?? null,
    campaignName: core.campaignName ?? null,
    objective: core.objective ?? null,
    materialTopic: core.materialTopic ?? null,
    destinationBrand: core.destinationBrand ?? null,
    orchestrationVersion: core.orchestrationVersion ?? null
  },
  production: {
    contentType: production.contentType ?? null,
    format: production.format ?? null,
    resolution: production.resolution ?? null,
    aspectRatio: production.aspectRatio ?? null,
    visualStyle: production.visualStyle ?? null,
    visualMood: production.visualMood ?? null,
    renderComplexity: production.renderComplexity ?? null
  },
  ai: {
    captionSeed: ai.captionSeed ?? null,
    hookSeed: ai.hookSeed ?? null,
    CTA: ai.CTA ?? null,
    hashtagSet: Array.isArray(ai.hashtagSet) ? ai.hashtagSet : [],
    variationCount: Number(ai.variationCount ?? 0),
    promptDirection: ai.promptDirection ?? null
  },
  distribution: {
    accountTypeTargets: Array.isArray(distribution.accountTypeTargets) ? distribution.accountTypeTargets : [],
    estimatedBatch: distribution.estimatedBatch ?? null,
    postingWindow: Array.isArray(distribution.postingWindow) ? distribution.postingWindow : [],
    distributionPriority: distribution.distributionPriority ?? null,
    targetPlatforms: Array.isArray(distribution.targetPlatforms) ? distribution.targetPlatforms : []
  },
  pipeline: {
    destinationPipeline: pipelineTargets,
    automationStage: pipeline.automationStage ?? null,
    orchestrationStatus: pipeline.orchestrationStatus ?? null
  }
};

const estimatedWorkload = {
  route: item.routing.route,
  batchSize: item.renderSpec.batchSize,
  renderRequired: item.renderSpec.requiresComfyUI,
  complexity: production.renderComplexity ?? 'unknown',
  workloadLabel: item.renderSpec.requiresComfyUI
    ? `${item.renderSpec.batchSize} render spec unit(s), simulation only`
    : `${item.renderSpec.batchSize} non-render orchestration unit(s)`
};

return [{
  json: {
    ok: true,
    validated: item.validation.validated,
    requestId: parsedSections.core.requestId,
    executionSummary: {
      requestId: parsedSections.core.requestId,
      orchestrationStage: parsedSections.pipeline.automationStage,
      detectedPipelineCount: pipelineTargets.length,
      estimatedWorkload,
      validationStatus: item.validation.validationStatus,
      validationErrors: item.validation.errors,
      validationWarnings: item.validation.warnings
    },
    parsedSections,
    routing: item.routing,
    renderSpec: item.renderSpec,
    renderSpecPreview: item.renderSpecPreview,
    mockAssetResult: item.mockAssetResult,
    blockedActions: [
      'real_comfyui_execution',
      'real_asset_generation',
      'auto_posting',
      'database_persistence'
    ],
    simulationOnly: true
  }
}];
